create table ticketnexus.persons_tbl (
    id           number generated by default as identity not null enable,
    username     varchar2(100 char) not null enable,
    first_name   varchar2(100 char),
    last_name    varchar2(100 char),
    email        varchar2(255 char),
    is_active_yn varchar2(1 char) default on null 'Y' not null enable
);

alter table ticketnexus.persons_tbl
    add constraint persons_pk primary key ( id )
        using index enable;

alter table ticketnexus.persons_tbl add constraint persons_uk1 unique ( username )
    using index enable;

